---播放被击和飘字
---@class LBattleSkillActHitWithHud
local LBattleSkillActHitWithHud = classX("LBattleSkillActHitWithHud", nil)


--[[
	player._skillHurtDataList 结构

	{
		--保持结构一致，不破坏战报时序
		{
			beforeList,
			hitHurt, --战报伤害结构 "hitType": 1,
			afterList,
		},
		{
			beforeList,
			hitHurt,
			afterList,
		},
	},
	{

	}
]]
---
---(0,0) 一次性飘完
---(0,index) 取第一块伤害列表的下标伤害
---(1,nil) 	取第一块伤害 (客户端多次伤害，战报只有一个伤害数据),支持多个目标，按groupIndex取对应伤害数据
---(2,index) 取第一块伤害列表的下标伤害(单目标,多子弹，伤害数据集中在第一块数据中，按序号一一对应取伤害)，支持多个目标，按groupIndex取对应伤害数据
---(3,index) 取第index块伤害(多目标,多子弹，伤害数据按目标id单独列出，按序号一一对应取伤害)
---如有遗漏的战报数据，在ShowRemainEffect()中集中处理
---@param player LBattleSkillPlayer
function LBattleSkillActHitWithHud.GetSkillHurtByType(player,type,index,groupIndex)
    type = type or 0
    index = index or 0
    local _skillHurtDataList = player:GetSkillHurtDataList() or {}
    if type == 0 then
        if index ==0 then
            local totalList = {baseEffectList={}}
            for k,v in pairs(_skillHurtDataList) do
                local showList = player:FormatShowHurtData(v)
                if showList then
                    for k1,v1 in ipairs(showList.baseEffectList) do
                        table.insert(totalList.baseEffectList,v1)
                    end
                end
            end
            player._tempSDataList = {}
            return totalList
        else
            player._tempSDataList[1] = nil
            local hurtDataList = _skillHurtDataList[1]
            if hurtDataList then
                local hurtData = hurtDataList[index]
                local tempSData = player._tempSDataList[1]
                if tempSData and tempSData.dataList then
                    tempSData.dataList[index] = nil
                end
                local resultList = player:FormatSingleShowData(hurtData)
                if player._playHudNum == index and player._playHudNum > 1 then
                    for i,v in ipairs(hurtDataList) do
                        if i > index then
                            local tHurtData = hurtDataList[i]
                            if tHurtData.afterList and #tHurtData.afterList > 0 then
                                for idx,val in ipairs(tHurtData.afterList) do
                                    if val.hurtEffect and val.hurtEffect.dead then
                                        table.insert(resultList.baseEffectList,val)
                                    end
                                end
                            end
                        end
                    end
                    return resultList
                else
                    return resultList
                end
            end
        end
    elseif type == 1 then
        player._tempSDataList[groupIndex] = nil
        local hurtList = _skillHurtDataList[groupIndex]
        return player:FormatShowHurtData(hurtList)
    elseif type == 2 or type == 3 then
        local hurtDataList = _skillHurtDataList[groupIndex]
        if not hurtDataList then return end
        local hurtData = hurtDataList[index]
        local tempSData = player._tempSDataList[groupIndex]
        if tempSData and tempSData.dataList then
            tempSData.dataList[index] = nil
        end
        return player:FormatSingleShowData(hurtData)

        --elseif type == 3 then
        --	player._tempSDataList[groupIndex] = nil
        --	local hurtDatalist = player._skillHurtDataList[groupIndex]
        --	if not hurtDatalist then
        --		return
        --	end
        --
        --	return player:FormatShowHurtData(hurtDatalist)
    end
end

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActHitWithHud.Execute(player,effData, playState)
    local effType = effData.effType
    local bHit = effType == LSkillEffConst.PLAY_EFF_HIT_HUD
    if bHit then
        local isNormal = player:IsNormal() --普攻还是技能
        bHit = isNormal and LFightConst.PLAY_HIT_ACTION_NORMAL or LFightConst.PLAY_HIT_ACTION_SKILL
    else
        bHit = LFightConst.PLAY_HIT_ACTION_NONE
    end

    local actionHurtDataList = LBattleSkillActHitWithHud.GetSkillHurtByType(player,playState.hurtDataType,playState.hurtDataIndex,playState.groupIndex)
    if not actionHurtDataList then return end

    local _recordPosOnHookIdMap = player:GetRecordPosOnHookIdMap()
    local _isPosOnHook = player:IsPosOnHook()
    local _viewMgr = player:GetViewMgr()
    local _recordSpecialMap = player:GetRecordSpecialMap()
    local _recordNoSkillHurtMap = player:GetRecordNoSkillHurtMap()
    local ignoreAllBeHtMap = player:GetIgnoreAllBeHtMap()

    if _isPosOnHook then
        local index = playState.index
        local atkUnitView = player:GetTargetAtkUnitView()
        local atkId = atkUnitView:GetId()
        local list = {}
        local state = false
        local targetId
        for i,effect in ipairs(actionHurtDataList.baseEffectList) do
            if atkId == effect.aId then
                local id = effect.eId
                local targetObj = _viewMgr:GetUnitView(id)
                if targetObj and targetObj:GetIndex() == index and effect.hurtEffect and ignoreAllBeHtMap[effect.hurtEffect.ht] and not _recordSpecialMap[id] then
                    _recordSpecialMap[id] = true
                    table.insert(list,effect)

                    local data = _recordNoSkillHurtMap[id]
                    if data and data.hurtEffect.dead then
                        table.insert(list,data)
                    end
                else
                    if not _recordSpecialMap[id] then
                        if targetId and targetId ~= id then break end
                        local tempTab = _recordPosOnHookIdMap[id]
                        if not tempTab or not tempTab[effType] then
                            if not tempTab then
                                tempTab = {}
                                _recordPosOnHookIdMap[id] = tempTab
                            end
                            table.insert(list,effect)
                            if not targetId then
                                targetId = id
                            end
                            state = true
                        end
                    end
                end
            end
        end

        if #list > 0 then
            local tempTab = _recordPosOnHookIdMap[targetId]
            if not tempTab then
                tempTab = {}
                _recordPosOnHookIdMap[targetId] = tempTab
            end
            tempTab[effType] = true

            actionHurtDataList.baseEffectList = list
        end
    end

    local effOffsetStart = effData.effOffsetStart
    local offset = Vector3(effOffsetStart.x,effOffsetStart.y, 0)
    _viewMgr:DealShowHurt({effectListArray = {actionHurtDataList}}, bHit,effData.playNum,offset,player)
end

return LBattleSkillActHitWithHud